{"content": "/* =========================================================
   Design Tokens
   ========================================================= */
:root {
  /* Palette */
  --color-bg: #0a0a0f;
  --color-surface: #12121a;
  --color-surface-2: #1a1a26;
  --color-border: #2a2a3a;
  --color-accent: #e94560;
  --color-accent-dim: rgba(233, 69, 96, 0.15);
  --color-text: #f0f0f5;
  --color-text-muted: #8888aa;
  --color-text-faint: #555570;

  /* Typography */
  --font-sans: "Inter", "Helvetica Neue", Arial, sans-serif;
  --font-mono: "JetBrains Mono", "Fira Code", monospace;

  --text-xs: 0.75rem;
  --text-sm: 0.875rem;
  --text-base: 1rem;
  --text-lg: 1.125rem;
  --text-xl: 1.25rem;
  --text-2xl: 1.5rem;
  --text-3xl: 1.875rem;
  --text-4xl: 2.25rem;
  --text-5xl: 3rem;
  --text-6xl: 3.75rem;

  --leading-tight: 1.15;
  --leading-snug: 1.35;
  --leading-normal: 1.6;

  /* Spacing */
  --space-1: 0.25rem;
  --space-2: 0.5rem;
  --space-3: 0.75rem;
  --space-4: 1rem;
  --space-6: 1.5rem;
  --space-8: 2rem;
  --space-12: 3rem;
  --space-16: 4rem;
  --space-20: 5rem;
  --space-24: 6rem;

  /* Layout */
  --container-max: 1200px;
  --container-pad: var(--space-6);
  --radius-sm: 4px;
  --radius-md: 8px;
  --radius-lg: 16px;

  /* Transitions */
  --transition-fast: 150ms ease;
  --transition-base: 250ms ease;
}

/* =========================================================
   Reset & Base
   ========================================================= */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  scroll-behavior: smooth;
  -webkit-text-size-adjust: 100%;
}

body {
  background-color: var(--color-bg);
  color: var(--color-text);
  font-family: var(--font-sans);
  font-size: var(--text-base);
  line-height: var(--leading-normal);
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

img,
svg {
  display: block;
  max-width: 100%;
}

a {
  color: inherit;
  text-decoration: none;
}

ul,
ol {
  list-style: none;
}

/* =========================================================
   Accessibility — Focus & Skip Link
   ========================================================= */
:focus-visible {
  outline: 2px solid var(--color-accent);
  outline-offset: 3px;
  border-radius: var(--radius-sm);
}

.skip-link {
  position: absolute;
  top: -100%;
  left: var(--space-4);
  padding: var(--space-2) var(--space-4);
  background: var(--color-accent);
  color: #fff;
  font-weight: 700;
  border-radius: var(--radius-md);
  z-index: 9999;
  transition: top var(--transition-fast);
}
.skip-link:focus {
  top: var(--space-4);
}

/* =========================================================
   Layout Helpers
   ========================================================= */
.container {
  width: 100%;
  max-width: var(--container-max);
  margin-inline: auto;
  padding-inline: var(--container-pad);
}

main {
  flex: 1;
}

/* =========================================================
   Site Header & Nav
   ========================================================= */
.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  background: rgba(10, 10, 15, 0.85);
  backdrop-filter: blur(12px);
  border-bottom: 1px solid var(--color-border);
}

.site-header__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  height: 64px;
}

.site-header__logo {
  font-size: var(--text-xl);
  font-weight: 800;
  letter-spacing: -0.03em;
  color: var(--color-text);
  transition: color var(--transition-fast);
}
.site-header__logo:hover {
  color: var(--color-accent);
}

.site-nav__list {
  display: flex;
  gap: var(--space-8);
}

.site-nav__link {
  font-size: var(--text-sm);
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-text-muted);
  transition: color var(--transition-fast);
  position: relative;
  padding-bottom: 2px;
}
.site-nav__link::after {
  content: "";
  position: absolute;
  bottom: -2px;
  left: 0;
  width: 0;
  height: 2px;
  background: var(--color-accent);
  transition: width var(--transition-base);
}
.site-nav__link:hover,
.site-nav__link[aria-current="page"] {
  color: var(--color-text);
}
.site-nav__link:hover::after,
.site-nav__link[aria-current="page"]::after {
  width: 100%;
}

/* Mobile nav */
.site-nav__toggle {
  display: none;
  background: none;
  border: 1px solid var(--color-border);
  border-radius: var(--radius-sm);
  padding: var(--space-2) var(--space-3);
  color: var(--color-text);
  cursor: pointer;
  font-size: var(--text-sm);
}

@media (max-width: 640px) {
  .site-nav__toggle {
    display: block;
  }
  .site-nav__list {
    display: none;
    position: absolute;
    top: 64px;
    left: 0;
    right: 0;
    background: var(--color-surface);
    border-bottom: 1px solid var(--color-border);
    flex-direction: column;
    gap: 0;
    padding: var(--space-4) 0;
  }
  .site-nav__list.is-open {
    display: flex;
  }
  .site-nav__link {
    display: block;
    padding: var(--space-3) var(--space-6);
    font-size: var(--text-base);
  }
  .site-nav__link::after {
    display: none;
  }
}

/* =========================================================
   Site Footer
   ========================================================= */
.site-footer {
  border-top: 1px solid var(--color-border);
  padding-block: var(--space-8);
  color: var(--color-text-muted);
  font-size: var(--text-sm);
}
.site-footer__inner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: var(--space-4);
}

/* =========================================================
   Hero Section (Landing)
   ========================================================= */
.hero {
  padding-block: var(--space-20) var(--space-16);
  text-align: center;
  position: relative;
  overflow: hidden;
}
.hero::before {
  content: "";
  position: absolute;
  top: -200px;
  left: 50%;
  transform: translateX(-50%);
  width: 800px;
  height: 800px;
  background: radial-gradient(circle, rgba(233, 69, 96, 0.12) 0%, transparent 70%);
  pointer-events: none;
}

.hero__eyebrow {
  display: inline-block;
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-accent);
  margin-bottom: var(--space-4);
}

.hero__heading {
  font-size: clamp(var(--text-4xl), 6vw, var(--text-6xl));
  font-weight: 900;
  line-height: var(--leading-tight);
  letter-spacing: -0.04em;
  margin-bottom: var(--space-6);
  max-width: 900px;
  margin-inline: auto;
}

.hero__subheading {
  font-size: clamp(var(--text-base), 2vw, var(--text-xl));
  color: var(--color-text-muted);
  max-width: 620px;
  margin-inline: auto;
  line-height: var(--leading-snug);
}

/* =========================================================
   Featured Episode
   ========================================================= */
.featured {
  padding-block: var(--space-16);
}

.featured__label {
  font-size: var(--text-xs);
  font-weight: 700;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--color-accent);
  margin-bottom: var(--space-6);
}

.featured__card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-lg);
  overflow: hidden;
  display: grid;
  grid-template-columns: 280px 1fr;
  transition: border-color var(--transition-base);
}
.featured__card:hover {
  border-color: var(--color-accent);
}

.featured__artwork {
  width: 280px;
  height: 280px;
  object-fit: cover;
  background: var(--color-surface-2);
}

.featured__body {
  padding: var(--space-8) var(--space-10);
  display: flex;
  flex-direction: column;
  justify-content: center;
  gap: var(--space-4);
}

.featured__meta {
  display: flex;
  align-items: center;
  gap: var(--space-4);
  font-size: var(--text-sm);
  color: var(--color-text-muted);
}

.featured__ep-number {
  font-weight: 700;
  color: var(--color-accent);
}

.featured__title {
  font-size: clamp(var(--text-2xl), 3vw, var(--text-3xl));
  font-weight: 800;
  line-height: var(--leading-tight);
  letter-spacing: -0.02em;
}

.featured__summary {
  font-size: var(--text-base);
  color: var(--color-text-muted);
  line-height: var(--leading-normal);
  max-width: 520px;
}

.featured__cta {
  margin-top: var(--space-2);
  display: inline-flex;
  align-items: center;
  gap: var(--space-2);
  background: var(--color-accent);
  color: #fff;
  font-weight: 700;
  font-size: var(--text-sm);
  letter-spacing: 0.04em;
  text-transform: uppercase;
  padding: var(--space-3) var(--space-6);
  border-radius: var(--radius-md);
  transition: opacity var(--transition-fast), transform var(--transition-fast);
  align-self: flex-start;
}
.featured__cta:hover {
  opacity: 0.88;
  transform: translateY(-1px);
}

@media (max-width: 768px) {
  .featured__card {
    grid-template-columns: 1fr;
  }
  .featured__artwork {
    width: 100%;
    height: 220px;
  }
  .featured__body {
    padding: var(--space-6);
  }
}

/* =========================================================
   Episode Card (Catalog)
   ========================================================= */
.episode-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(300px, 1fr));
  gap: var(--space-6);
  padding-block: var(--space-8);
}

.episode-card {
  background: var(--color-surface);
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  overflow: hidden;
  display: flex;
  flex-direction: column;
  transition: border-color var(--transition-base), transform var(--transition-base);
}
.episode-card:hover {
  border-color: var(--color-accent);
  transform: translateY(-2px);
}

.episode-card__artwork {
  width: 100%;
  aspect-ratio: 1;
  object-fit: cover;
  background: var(--color-surface-2);
}

.episode-card__body {
  padding: var(--space-5);
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--space-3);
}

.episode-card__meta {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  font-size: var(--text-xs);
  color: var(--color-text-muted);
}

.episode-card__ep {
  font-weight: 700;
  color: var(--color-accent);
  font-size: var(--text-xs);
  letter-spacing: 0.06em;
  text-transform: uppercase;
}

.episode-card__title {
  font-size: var(--text-lg);
  font-weight: 700;
  line-height: var(--leading-snug);
  letter-spacing: -0.01em;
}

.episode-card__summary {
  font-size: var(--text-sm);
  color: var(--color-text-muted);
  line-height: var(--leading-normal);
  flex: 1;
}

.episode-card__footer {
  display: flex;
  align-items: center;
  gap: var(--space-3);
  margin-top: var(--space-2);
  font-size: var(--text-xs);
  color: var(--color-text-faint);
  border-top: 1px solid var(--color-border);
  padding-top: var(--space-3);
}

/* =========================================================
   Episodes Page
   ========================================================= */
.page-header {
  padding-block: var(--space-16) var(--space-6);
  border-bottom: 1px solid var(--color-border);
}

.page-header__heading {
  font-size: clamp(var(--text-3xl), 5vw, var(--text-5xl));
  font-weight: 900;
  letter-spacing: -0.04em;
  line-height: var(--leading-tight);
  margin-bottom: var(--space-3);
}

.page-header__subheading {
  font-size: var(--text-lg);
  color: var(--color-text-muted);
}

/* =========================================================
   About Page
   ========================================================= */
.about-section {
  padding-block: var(--space-16);
  max-width: 720px;
}

.about-section + .about-section {
  border-top: 1px solid var(--color-border);
}

.about-section__heading {
  font-size: var(--text-2xl);
  font-weight: 800;
  letter-spacing: -0.02em;
  margin-bottom: var(--space-4);
  color: var(--color-text);
}

.about-section__body {
  font-size: var(--text-lg);
  color: var(--color-text-muted);
  line-height: var(--leading-normal);
}

.about-page-heading {
  padding-block: var(--space-16) var(--space-8);
}

/* =========================================================
   FAQ Page
   ========================================================= */
.faq-page {
  padding-block: var(--space-16);
}

.faq-list {
  max-width: 720px;
  display: flex;
  flex-direction: column;
  gap: var(--space-1);
  margin-top: var(--space-8);
}

.faq-item {
  border: 1px solid var(--color-border);
  border-radius: var(--radius-md);
  overflow: hidden;
}

.faq-item__question {
  width: 100%;
  background: var(--color-surface);
  border: none;
  text-align: left;
  padding: var(--space-5) var(--space-6);
  font-size: var(--text-base);
  font-weight: 600;
  color: var(--color-text);
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-4);
  transition: background var(--transition-fast);
  font-family: var(--font-sans);
}
.faq-item__question:hover {
  background: var(--color-surface-2);
}

.faq-item__icon {
  flex-shrink: 0;
  width: 20px;
  height: 20px;
  color: var(--color-accent);
  transition: transform var(--transition-base);
}
.faq-item__icon--open {
  transform: rotate(45deg);
}

.faq-item__answer {
  padding: 0 var(--space-6) var(--space-5);
  font-size: var(--text-base);
  color: var(--color-text-muted);
  line-height: var(--leading-normal);
  background: var(--color-surface);
}

/* =========================================================
   Responsive Utilities
   ========================================================= */
@media (max-width: 480px) {
  :root {
    --container-pad: var(--space-4);
  }
  .hero {
    padding-block: var(--space-12) var(--space-8);
  }
  .page-header {
    padding-block: var(--space-8) var(--space-4);
  }
  .about-section {
    padding-block: var(--space-8);
  }
  .faq-page {
    padding-block: var(--space-8);
  }
}
